165	    public ResequenceDefinition timeout(String timeout) {
166	        if (streamConfig != null) {
167	            streamConfig.setTimeout(timeout);
168	        } else {
169	            // initialize batch mode as its default mode
170	            if (batchConfig == null) {
171	                batch();
