72	        Processor processor = this.createChildProcessor(true);
73	        Expression expression = createExpression(definition.getExpression());
74	
75	        // and wrap in unit of work
76	        AsyncProcessor target = PluginHelper.getInternalProcessorFactory(camelContext)
77	                .addUnitOfWorkProcessorAdvice(camelContext, processor, route);
78	
79	        ObjectHelper.notNull(config, "config", this);
80	        ObjectHelper.notNull(expression, "expression", this);
81	
82	        boolean isReverse = parseBoolean(config.getReverse(), false);
83	        boolean isAllowDuplicates = parseBoolean(config.getAllowDuplicates(), false);
84	
85	        Resequencer resequencer = new Resequencer(camelContext, target, expression, isAllowDuplicates, isReverse);
86	        resequencer.setDisabled(isDisabled(camelContext, definition));
87	        Integer num = parseInt(config.getBatchSize());
88	        if (num != null) {
89	            resequencer.setBatchSize(num);
90	        }
91	        Long dur = parseDuration(config.getBatchTimeout());
92	        if (dur != null) {
93	            resequencer.setBatchTimeout(dur);
94	        }
95	        resequencer.setReverse(isReverse);
96	        resequencer.setAllowDuplicates(isAllowDuplicates);
97	        if (config.getIgnoreInvalidExchanges() != null) {
98	            resequencer.setIgnoreInvalidExchanges(parseBoolean(config.getIgnoreInvalidExchanges(), false));
99	        }
100	        return resequencer;
101	    }
